export default function initChatbot() {
  const toggleBtn = document.getElementById("chatbot-toggle");
  const chatWindow = document.getElementById("chatbot-window");
  const closeBtn = document.getElementById("chatbot-close");
  const settingsToggle = document.getElementById("chatbot-settings-toggle");
  const settingsPanel = document.getElementById("chatbot-settings-panel");
  const settingsBack = document.getElementById("chatbot-settings-back");
  const apiKeyInput = document.getElementById("chatbot-api-key");
  const saveKeyBtn = document.getElementById("chatbot-save-key");
  const messagesDiv = document.getElementById("chatbot-messages");
  const chatForm = document.getElementById("chatbot-form");
  const chatInput = document.getElementById("chatbot-input");
  const chipsContainer = document.getElementById("chatbot-chips");

  let apiKey = localStorage.getItem("gemini_api_key") || "";
  if (apiKey) {
    apiKeyInput.value = apiKey;
  }

  // Toggle Chat window
  toggleBtn.addEventListener("click", () => {
    chatWindow.classList.toggle("hidden");
    if (!chatWindow.classList.contains("hidden")) {
      chatInput.focus();
      scrollToBottom();
    }
  });

  // Close Chat
  closeBtn.addEventListener("click", () => {
    chatWindow.classList.add("hidden");
  });

  // Settings Panel Navigation
  settingsToggle.addEventListener("click", () => {
    settingsPanel.classList.toggle("hidden");
  });

  settingsBack.addEventListener("click", () => {
    settingsPanel.classList.add("hidden");
  });

  // Save API Key
  saveKeyBtn.addEventListener("click", () => {
    const key = apiKeyInput.value.trim();
    if (key) {
      localStorage.setItem("gemini_api_key", key);
      apiKey = key;
      alert("Gemini API key saved! Chat upgraded to Live AI Mode.");
    } else {
      localStorage.removeItem("gemini_api_key");
      apiKey = "";
      alert("API key cleared. Chat reverted to local Knowledge Mode.");
    }
    settingsPanel.classList.add("hidden");
  });

  // Form Submission
  chatForm.addEventListener("submit", (e) => {
    e.preventDefault();
    const query = chatInput.value.trim();
    if (!query) return;

    handleUserMessage(query);
  });

  // Quick Chips Buttons
  chipsContainer.addEventListener("click", (e) => {
    if (e.target.classList.contains("chip-btn")) {
      const query = e.target.getAttribute("data-query");
      handleUserMessage(query);
    }
  });

  function handleUserMessage(query) {
    appendMessage(query, "user");
    chatInput.value = "";
    
    // Hide suggested chips after first interaction
    chipsContainer.style.display = "none";

    showTypingIndicator();

    setTimeout(() => {
      resolveBotResponse(query)
        .then((response) => {
          removeTypingIndicator();
          appendMessage(response, "bot");
        })
        .catch((err) => {
          console.error(err);
          removeTypingIndicator();
          appendMessage(getLocalFallbackResponse(query), "bot");
        });
    }, 800);
  }

  function appendMessage(text, sender) {
    const msgDiv = document.createElement("div");
    msgDiv.className = `message ${sender}`;
    msgDiv.innerHTML = `<div class="message-content">${linkify(text)}</div>`;
    messagesDiv.appendChild(msgDiv);
    scrollToBottom();
  }

  function showTypingIndicator() {
    const indicator = document.createElement("div");
    indicator.id = "chatbot-typing";
    indicator.className = "message bot";
    indicator.innerHTML = `
      <div class="message-content typing-indicator">
        <span></span>
        <span></span>
        <span></span>
      </div>
    `;
    messagesDiv.appendChild(indicator);
    scrollToBottom();
  }

  function removeTypingIndicator() {
    const indicator = document.getElementById("chatbot-typing");
    if (indicator) {
      indicator.remove();
    }
  }

  function scrollToBottom() {
    messagesDiv.scrollTop = messagesDiv.scrollHeight;
  }

  function linkify(text) {
    const urlPattern = /(\b(https?|ftp|file):\/\/[-A-Z0-9+&@#\/%?=~_|!:,.;]*[-A-Z0-9+&@#\/%=~_|])/ig;
    return text.replace(urlPattern, '<a href="$1" target="_blank" rel="noopener noreferrer" style="color: #00f2fe; text-decoration: underline;">$1</a>');
  }

  // Response Resolving (Local Fallback vs Gemini API)
  async function resolveBotResponse(query) {
    if (!apiKey) {
      return getLocalFallbackResponse(query);
    }

    try {
      const response = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${apiKey}`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify({
            contents: [
              {
                role: "user",
                parts: [
                  { text: `${systemPrompt}\n\nUser Question: ${query}` }
                ]
              }
            ],
            generationConfig: {
              maxOutputTokens: 150,
              temperature: 0.7
            }
          })
        }
      );

      if (!response.ok) {
        throw new Error("Gemini API call failed");
      }

      const data = await response.json();
      return data.candidates[0].content.parts[0].text.trim();
    } catch (error) {
      console.warn("Falling back to local knowledge resolution:", error);
      return getLocalFallbackResponse(query);
    }
  }

  function getLocalFallbackResponse(query) {
    const lowerQuery = query.toLowerCase();

    if (lowerQuery.includes("skill") || lowerQuery.includes("technologies") || lowerQuery.includes("languages")) {
      return resumeKnowledge.skills;
    }
    if (lowerQuery.includes("stampede") || lowerQuery.includes("crowd") || lowerQuery.includes("density") || lowerQuery.includes("prevention")) {
      return resumeKnowledge.stampede;
    }
    if (lowerQuery.includes("floatchat") || lowerQuery.includes("ocean")) {
      return resumeKnowledge.floatchat;
    }
    if (lowerQuery.includes("query") || lowerQuery.includes("student") || lowerQuery.includes("chatbot") || lowerQuery.includes("bot")) {
      return resumeKnowledge.querybot;
    }
    if (lowerQuery.includes("resume") || lowerQuery.includes("cv") || lowerQuery.includes("download")) {
      return resumeKnowledge.resume;
    }
    if (lowerQuery.includes("experience") || lowerQuery.includes("work") || lowerQuery.includes("intern")) {
      return resumeKnowledge.experience;
    }
    if (lowerQuery.includes("education") || lowerQuery.includes("college") || lowerQuery.includes("chennai") || lowerQuery.includes("degree")) {
      return resumeKnowledge.education;
    }
    if (lowerQuery.includes("contact") || lowerQuery.includes("email") || lowerQuery.includes("reach") || lowerQuery.includes("phone")) {
      return resumeKnowledge.contact;
    }
    if (lowerQuery.includes("leetcode") || lowerQuery.includes("rating")) {
      return resumeKnowledge.leetcode;
    }

    return "I'm running in Knowledge Mode. You can ask me about Suhith's 'skills', 'experience', 'education', 'contact info', 'resume', or his specific projects ('stampede prevention', 'floatchat', or 'student chatbot'). To upgrade me to a fully conversational AI, click the settings cog at the top and enter a Gemini API Key.";
  }
}
