import { portfolioConfig } from "../portfolio.config";

export default function injectConfig() {
  // Update document metadata
  document.title = `${portfolioConfig.name} | ${portfolioConfig.title}`;
  
  const descriptionMeta = document.querySelector('meta[name="description"]');
  if (descriptionMeta) {
    descriptionMeta.setAttribute("content", portfolioConfig.description);
  }
  
  const keywordsMeta = document.querySelector('meta[name="keywords"]');
  if (keywordsMeta) {
    keywordsMeta.setAttribute("content", `${portfolioConfig.name}, portfolio, developer, AI, Full-Stack`);
  }

  // Update elements with data-src attributes
  const srcElements = document.querySelectorAll("[data-src]");
  srcElements.forEach((el) => {
    let val = el.getAttribute("data-src");
    let updated = val;
    if (updated.includes("PROFILE_IMAGE_URL")) {
      updated = updated.replace(/PROFILE_IMAGE_URL/g, portfolioConfig.profileImage);
    }
    if (updated.includes("STAMPEDE_IMAGE_URL")) {
      updated = updated.replace(/STAMPEDE_IMAGE_URL/g, portfolioConfig.projects.stampede);
    }
    if (updated.includes("FLOATCHAT_IMAGE_URL")) {
      updated = updated.replace(/FLOATCHAT_IMAGE_URL/g, portfolioConfig.projects.floatchat);
    }
    if (updated.includes("QUERYBOT_IMAGE_URL")) {
      updated = updated.replace(/QUERYBOT_IMAGE_URL/g, portfolioConfig.projects.queryBot);
    }
    el.setAttribute("src", updated);
  });

  // Update elements with data-href attributes
  const hrefElements = document.querySelectorAll("[data-href]");
  hrefElements.forEach((el) => {
    let val = el.getAttribute("data-href");
    let updated = val;
    if (updated.includes("RESUME_URL")) {
      updated = updated.replace(/RESUME_URL/g, portfolioConfig.resume);
    }
    el.setAttribute("href", updated);
  });

  // Inject contact form action
  const contactForm = document.getElementById("contact-form");
  if (contactForm && portfolioConfig.formspreeId) {
    contactForm.setAttribute("action", `https://formspree.io/f/${portfolioConfig.formspreeId}`);
  }
}
